async function a(t){const n=t.apiKey.trim();if(!n)throw new Error("OpenRouter API key is missing. Add it in AI Models or Settings.");const e=await fetch("https://openrouter.ai/api/v1/chat/completions",{method:"POST",headers:{Authorization:`Bearer ${n}`,"Content-Type":"application/json","HTTP-Referer":"https://github.com/surelle-ha/vindicta","X-Title":"Vindicta"},body:JSON.stringify({model:t.model||"openai/gpt-4.1-mini",messages:t.messages,temperature:.4})});if(!e.ok){const o=await e.text().catch(()=>"");throw new Error(o||`OpenRouter returned HTTP ${e.status}`)}const r=(await e.json())?.choices?.[0]?.message?.content;if(typeof r!="string"||!r.trim())throw new Error("OpenRouter returned an empty response.");return r}export{a as r};
